import{_ as t,o as a,c as s,a3 as n}from"./chunks/framework.Df0_fMVA.js";const u=JSON.parse('{"title":"Best Practices","description":"","frontmatter":{},"headers":[],"relativePath":"guide/best-practices.md","filePath":"guide/best-practices.md"}'),o={name:"guide/best-practices.md"};function i(r,e,d,l,c,p){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h1><p>Practical tips for getting the most out of Specialist Agent and Claude Code. These are patterns validated across real projects — not generic advice.</p><h2 id="planning" tabindex="-1">Planning <a class="header-anchor" href="#planning" aria-label="Permalink to &quot;Planning&quot;">​</a></h2><h3 id="always-start-in-plan-mode" tabindex="-1">Always Start in Plan Mode <a class="header-anchor" href="#always-start-in-plan-mode" aria-label="Permalink to &quot;Always Start in Plan Mode&quot;">​</a></h3><p>Before writing code, use plan mode or <code>@planner</code> to define scope. This prevents wasted tokens on wrong approaches.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;Use @planner to plan the checkout flow with payments and email notifications&quot;</span></span></code></pre></div><p>For unclear scope, use <code>/discovery</code> first — it evaluates feasibility and gives a GO/NO-GO verdict before any code is written.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;/discovery — we need a referral system with rewards, tracking, and analytics&quot;</span></span></code></pre></div><h3 id="let-claude-interview-you" tabindex="-1">Let Claude Interview You <a class="header-anchor" href="#let-claude-interview-you" aria-label="Permalink to &quot;Let Claude Interview You&quot;">​</a></h3><p>Instead of writing a long prompt, ask the agent to interview you. This surfaces requirements you&#39;d miss:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;Use @analyst to interview me about the requirements for user onboarding&quot;</span></span></code></pre></div><p>The <code>@analyst</code> agent uses the <code>AskUserQuestion</code> tool to ask targeted questions before producing specs.</p><h3 id="phase-gated-plans" tabindex="-1">Phase-Gated Plans <a class="header-anchor" href="#phase-gated-plans" aria-label="Permalink to &quot;Phase-Gated Plans&quot;">​</a></h3><p>Break complex features into phases with verification at each gate:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Phase 1: Data model + API → run tests → checkpoint</span></span>
<span class="line"><span>Phase 2: UI components → run tests → checkpoint</span></span>
<span class="line"><span>Phase 3: Integration → run e2e tests → checkpoint</span></span></code></pre></div><p>Use <code>@executor</code> for automatic checkpoint management and cost tracking across phases.</p><h2 id="context-management" tabindex="-1">Context Management <a class="header-anchor" href="#context-management" aria-label="Permalink to &quot;Context Management&quot;">​</a></h2><h3 id="compact-at-50-—-not-90" tabindex="-1">Compact at 50% — Not 90% <a class="header-anchor" href="#compact-at-50-—-not-90" aria-label="Permalink to &quot;Compact at 50% — Not 90%&quot;">​</a></h3><p>Claude Code&#39;s quality degrades as context fills up. Don&#39;t wait for warnings.</p><table tabindex="0"><thead><tr><th>Context Usage</th><th>Quality</th><th>Action</th></tr></thead><tbody><tr><td>0-50%</td><td>Optimal</td><td>Keep working</td></tr><tr><td>50-70%</td><td>Declining</td><td>Run <code>/compact</code> now</td></tr><tr><td>70%+</td><td>Degraded</td><td><code>/compact</code> or <code>/clear</code> and restart</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Specialist Agent Advantage</p><p><code>@orchestrator</code> avoids this problem entirely — each subagent gets fresh context via <strong>Context Isolation Protocol</strong>. A 5-agent orchestration never hits context limits.</p></div><h3 id="one-agent-one-task" tabindex="-1">One Agent, One Task <a class="header-anchor" href="#one-agent-one-task" aria-label="Permalink to &quot;One Agent, One Task&quot;">​</a></h3><p>Don&#39;t overload a single conversation with unrelated tasks. Instead:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Bad — context pollution</span></span>
<span class="line"><span>&quot;Build the auth module, then review the payments module, then debug the cart&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Good — focused agents</span></span>
<span class="line"><span>&quot;Use @builder to create the auth module&quot;        # conversation 1</span></span>
<span class="line"><span>&quot;Use @reviewer to review the payments module&quot;    # conversation 2</span></span>
<span class="line"><span>&quot;Use @doctor to investigate the cart bug&quot;        # conversation 3</span></span></code></pre></div><p>For multi-part work in a single session, use <code>@orchestrator</code> — it spawns isolated subagents automatically.</p><h3 id="use-rename-and-resume-for-long-projects" tabindex="-1">Use /rename and /resume for Long Projects <a class="header-anchor" href="#use-rename-and-resume-for-long-projects" aria-label="Permalink to &quot;Use /rename and /resume for Long Projects&quot;">​</a></h3><p>Name important sessions so you can return to them:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/rename &quot;auth-module-v2&quot;</span></span>
<span class="line"><span># ... days later ...</span></span>
<span class="line"><span>/resume &quot;auth-module-v2&quot;</span></span></code></pre></div><h2 id="agent-selection" tabindex="-1">Agent Selection <a class="header-anchor" href="#agent-selection" aria-label="Permalink to &quot;Agent Selection&quot;">​</a></h2><h3 id="when-to-use-which-agent" tabindex="-1">When to Use Which Agent <a class="header-anchor" href="#when-to-use-which-agent" aria-label="Permalink to &quot;When to Use Which Agent&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Situation</th><th>Best Choice</th><th>Why</th></tr></thead><tbody><tr><td>Scope is unclear</td><td><code>/discovery</code></td><td>Evaluates feasibility before committing tokens</td></tr><tr><td>Need a plan</td><td><code>@planner</code></td><td>Structured phases with acceptance criteria</td></tr><tr><td>Simple build task</td><td><code>@builder</code></td><td>Direct execution, no overhead</td></tr><tr><td>3+ parallel tasks</td><td><code>@orchestrator</code></td><td>Spawns subagents, prevents conflicts</td></tr><tr><td>Complex execution</td><td><code>@executor</code></td><td>Checkpoints, cost tracking, quality gates</td></tr><tr><td>Code looks wrong</td><td><code>@reviewer</code></td><td>3-in-1 review with automated checks</td></tr><tr><td>Something is broken</td><td><code>@doctor</code></td><td>4-phase diagnosis with evidence</td></tr><tr><td>Quick prototype</td><td><code>@builder</code> (Lite)</td><td>Faster, cheaper, good enough for iteration</td></tr></tbody></table><h3 id="full-vs-lite-—-decision-matrix" tabindex="-1">Full vs Lite — Decision Matrix <a class="header-anchor" href="#full-vs-lite-—-decision-matrix" aria-label="Permalink to &quot;Full vs Lite — Decision Matrix&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Task</th><th>Use Full</th><th>Use Lite</th></tr></thead><tbody><tr><td>PR review</td><td>Yes</td><td>No</td></tr><tr><td>Migration</td><td>Yes</td><td>No</td></tr><tr><td>Bug investigation</td><td>Yes</td><td>No</td></tr><tr><td>Component scaffold</td><td>No</td><td>Yes</td></tr><tr><td>Quick copy change</td><td>No</td><td>Yes</td></tr><tr><td>Prototype</td><td>No</td><td>Yes</td></tr><tr><td>Marketing copy</td><td>No</td><td>Yes</td></tr></tbody></table><h3 id="vanilla-claude-code-vs-agents" tabindex="-1">Vanilla Claude Code vs Agents <a class="header-anchor" href="#vanilla-claude-code-vs-agents" aria-label="Permalink to &quot;Vanilla Claude Code vs Agents&quot;">​</a></h3><p>For simple, single-file tasks, vanilla Claude Code (no agent) is often faster:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># No agent needed — just ask directly</span></span>
<span class="line"><span>&quot;Add a loading spinner to the LoginButton component&quot;</span></span>
<span class="line"><span>&quot;Fix the typo in the error message on line 42&quot;</span></span>
<span class="line"><span>&quot;Add TypeScript types to this function&quot;</span></span></code></pre></div><p>Use agents when the task involves <strong>multiple files</strong>, <strong>verification steps</strong>, or <strong>domain expertise</strong> (security, performance, payments).</p><h2 id="debugging" tabindex="-1">Debugging <a class="header-anchor" href="#debugging" aria-label="Permalink to &quot;Debugging&quot;">​</a></h2><h3 id="share-screenshots" tabindex="-1">Share Screenshots <a class="header-anchor" href="#share-screenshots" aria-label="Permalink to &quot;Share Screenshots&quot;">​</a></h3><p>When stuck on visual bugs, take a screenshot and share it with Claude. Visual context resolves issues faster than describing them:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;Here&#39;s a screenshot of the layout bug — the sidebar overlaps the main content on mobile&quot;</span></span></code></pre></div><h3 id="use-mcp-for-browser-debugging" tabindex="-1">Use MCP for Browser Debugging <a class="header-anchor" href="#use-mcp-for-browser-debugging" aria-label="Permalink to &quot;Use MCP for Browser Debugging&quot;">​</a></h3><p>Connect browser tools via MCP so agents can see console logs and network errors directly:</p><table tabindex="0"><thead><tr><th>MCP</th><th>What It Gives Agents</th></tr></thead><tbody><tr><td><strong>Playwright</strong></td><td>Automated browser testing, screenshots</td></tr><tr><td><strong>Chrome DevTools</strong></td><td>Console logs, network tab, DOM inspection</td></tr></tbody></table><p>See <a href="/pr-preview/pr-79/guide/mcp-integrations.html#complementary-tools">MCP Integrations</a> for setup.</p><h3 id="run-background-tasks-for-live-debugging" tabindex="-1">Run Background Tasks for Live Debugging <a class="header-anchor" href="#run-background-tasks-for-live-debugging" aria-label="Permalink to &quot;Run Background Tasks for Live Debugging&quot;">​</a></h3><p>Ask Claude to run your dev server as a background task, then debug against it:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;Run the dev server in background, then test the login flow and check for errors&quot;</span></span></code></pre></div><h2 id="cost-optimization" tabindex="-1">Cost Optimization <a class="header-anchor" href="#cost-optimization" aria-label="Permalink to &quot;Cost Optimization&quot;">​</a></h2><h3 id="smart-model-selection" tabindex="-1">Smart Model Selection <a class="header-anchor" href="#smart-model-selection" aria-label="Permalink to &quot;Smart Model Selection&quot;">​</a></h3><p><code>@executor</code> automatically selects the cheapest appropriate model:</p><table tabindex="0"><thead><tr><th>Task Type</th><th>Model</th><th>Why</th></tr></thead><tbody><tr><td>Boilerplate, CRUD, templates</td><td>Haiku</td><td>Fast, cheap, reliable for simple patterns</td></tr><tr><td>Business logic, components</td><td>Sonnet</td><td>Good balance of quality and cost</td></tr><tr><td>Architecture, complex debugging</td><td>Opus</td><td>Maximum reasoning for hard problems</td></tr></tbody></table><h3 id="estimate-before-executing" tabindex="-1">Estimate Before Executing <a class="header-anchor" href="#estimate-before-executing" aria-label="Permalink to &quot;Estimate Before Executing&quot;">​</a></h3><p>Use <code>/estimate</code> before expensive operations:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;/estimate — migrate 15 Vue 2 components to Vue 3 Composition API&quot;</span></span></code></pre></div><p>This gives you token and cost projections before committing.</p><h3 id="checkpoint-often" tabindex="-1">Checkpoint Often <a class="header-anchor" href="#checkpoint-often" aria-label="Permalink to &quot;Checkpoint Often&quot;">​</a></h3><p>Checkpoints are cheap insurance. If an agent goes off track, <code>Esc Esc</code> or <code>/rewind</code> takes you back instantly instead of re-doing work.</p><p><code>@executor</code> creates checkpoints automatically after every task. For manual work, commit often — at least once per hour of work.</p><h2 id="multi-agent-workflows" tabindex="-1">Multi-Agent Workflows <a class="header-anchor" href="#multi-agent-workflows" aria-label="Permalink to &quot;Multi-Agent Workflows&quot;">​</a></h2><h3 id="always-plan-before-orchestrating" tabindex="-1">Always Plan Before Orchestrating <a class="header-anchor" href="#always-plan-before-orchestrating" aria-label="Permalink to &quot;Always Plan Before Orchestrating&quot;">​</a></h3><p>Never jump to <code>@orchestrator</code> without a plan:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Bad — orchestrator without direction</span></span>
<span class="line"><span>&quot;Use @orchestrator to build the dashboard&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Good — plan first, then execute</span></span>
<span class="line"><span>&quot;Use @planner to plan the dashboard feature&quot;</span></span>
<span class="line"><span># ... review the plan ...</span></span>
<span class="line"><span>&quot;Use @orchestrator to execute this plan&quot;</span></span></code></pre></div><h3 id="use-handoff-templates" tabindex="-1">Use Handoff Templates <a class="header-anchor" href="#use-handoff-templates" aria-label="Permalink to &quot;Use Handoff Templates&quot;">​</a></h3><p>When agents pass work to each other, structured handoffs prevent context loss:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@builder completes → Standard Handoff → @reviewer receives</span></span>
<span class="line"><span>@reviewer finds bugs → QA FAIL Handoff → @builder receives with specific issues</span></span>
<span class="line"><span>@reviewer approves → QA PASS Handoff → ready for merge</span></span></code></pre></div><p><code>@orchestrator</code> and <code>@executor</code> use these templates automatically. See <a href="/pr-preview/pr-79/scenarios/workflows.html">Multi-Agent Workflows</a> for detailed examples.</p><h3 id="verify-at-boundaries" tabindex="-1">Verify at Boundaries <a class="header-anchor" href="#verify-at-boundaries" aria-label="Permalink to &quot;Verify at Boundaries&quot;">​</a></h3><p>Every agent transition is a potential failure point. Always verify after:</p><ol><li><code>@builder</code> finishes → run tests before sending to <code>@reviewer</code></li><li><code>@reviewer</code> approves → run full build before merging</li><li><code>@migrator</code> completes → run original test suite to verify no regressions</li></ol><p>Use <code>/verify</code> to enforce evidence-based verification.</p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><h3 id="keep-claude-md-under-200-lines" tabindex="-1">Keep CLAUDE.md Under 200 Lines <a class="header-anchor" href="#keep-claude-md-under-200-lines" aria-label="Permalink to &quot;Keep CLAUDE.md Under 200 Lines&quot;">​</a></h3><p>A bloated <code>CLAUDE.md</code> wastes context on every interaction. Keep it focused:</p><ul><li><strong>Do include:</strong> Project-specific conventions, directory structure, key decisions</li><li><strong>Don&#39;t include:</strong> Generic best practices, framework documentation, obvious rules</li></ul><p>For detailed rules, use <code>.claude/rules/</code> files — they load on-demand instead of always.</p><h3 id="use-claude-rules-for-detailed-instructions" tabindex="-1">Use .claude/rules/ for Detailed Instructions <a class="header-anchor" href="#use-claude-rules-for-detailed-instructions" aria-label="Permalink to &quot;Use .claude/rules/ for Detailed Instructions&quot;">​</a></h3><p>Split large instruction sets into topic-specific rule files:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.claude/rules/</span></span>
<span class="line"><span>  testing.md        # Testing conventions</span></span>
<span class="line"><span>  api-patterns.md   # API design rules</span></span>
<span class="line"><span>  naming.md         # Naming conventions</span></span></code></pre></div><p>These load based on context relevance, saving tokens compared to putting everything in <code>CLAUDE.md</code>.</p><h3 id="use-permissions-instead-of-dangerously-skip-permissions" tabindex="-1">Use /permissions Instead of --dangerously-skip-permissions <a class="header-anchor" href="#use-permissions-instead-of-dangerously-skip-permissions" aria-label="Permalink to &quot;Use /permissions Instead of --dangerously-skip-permissions&quot;">​</a></h3><p>Set granular permissions with wildcard syntax instead of disabling safety:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/permissions</span></span>
<span class="line"><span># Allow read/write in src/</span></span>
<span class="line"><span># Allow running npm test, npm run build</span></span>
<span class="line"><span># Block rm -rf, git push --force</span></span></code></pre></div><h2 id="daily-workflow" tabindex="-1">Daily Workflow <a class="header-anchor" href="#daily-workflow" aria-label="Permalink to &quot;Daily Workflow&quot;">​</a></h2><h3 id="start-sessions-right" tabindex="-1">Start Sessions Right <a class="header-anchor" href="#start-sessions-right" aria-label="Permalink to &quot;Start Sessions Right&quot;">​</a></h3><ol><li>Check git status — clean working tree before starting</li><li>Pull latest changes — <code>git pull</code> to avoid conflicts</li><li>Start with plan mode for new features</li><li>Use <code>/onboard</code> when returning to unfamiliar code</li></ol><h3 id="end-sessions-right" tabindex="-1">End Sessions Right <a class="header-anchor" href="#end-sessions-right" aria-label="Permalink to &quot;End Sessions Right&quot;">​</a></h3><ol><li>Commit work in progress — don&#39;t lose changes</li><li>Run tests — verify nothing is broken</li><li><code>/rename</code> the session if you&#39;ll continue later</li><li>Note any open items for the next session</li></ol><h2 id="what-s-next" tabindex="-1">What&#39;s Next? <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s Next?&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-79/scenarios/workflows.html">Multi-Agent Workflows</a> — Real-world orchestration examples with cost estimates</li><li><a href="/pr-preview/pr-79/guide/agent-composition.html">Agent Composition</a> — How agents work together</li><li><a href="/pr-preview/pr-79/guide/benchmark.html">Performance &amp; Cost</a> — Token usage optimization</li><li><a href="/pr-preview/pr-79/guide/faq.html">FAQ</a> — Common questions answered</li></ul>`,90)])])}const g=t(o,[["render",i]]);export{u as __pageData,g as default};
